        let mut q = self.queue.lock().unwrap();
        while q.is_empty() { q = self.not_empty.wait(q).unwrap(); }
        let v = q.pop_front().unwrap();
        self.not_full.notify_one();
        v
    }

    fn size(&self) -> usize { self.queue.lock().unwrap().len() }
}

